UPDATE knowledge_resource
knowledge_base_id = #{knowledgeBaseId}, resource_type = #{resourceType}, title = #{title}, description = #{description}, url = #{url}, local_path = #{localPath}, cover_url = #{coverUrl}, size = #{size}, duration = #{duration}, updated_at = #{updatedAt}, is_deleted = #{isDeleted}, metadata = #{metadata,typeHandler=cn.yifan.drawsee.typehandler.JsonTypeHandler},
